if (!$env.GDA_API_KEY_2026 || !$env.GDA_DEPLOY_KEY_2026 || !$env.GDA_WEBHOOK_SECRET_2026) throw new Error('2026 auth env vars not set');
const h = $input.first().json.headers || {};
const b = $input.first().json.body || {};
const auth = h['x-gda-auth'] || h['x-gda-key'] || b.auth_key || '';
const origin = (h.origin || h.referer || '').toLowerCase();
const trusted = ['gda.csr-llc.tech','n8n.csr-llc.tech','localhost'];
if (auth !== $env.GDA_API_KEY_2026 && !trusted.some(o => origin.includes(o))) throw new Error('Unauthorized');
return $input.all();

const body = $('Webhook').first().json.body || {};
const samRaw = $('Fetch SAM Entity').first().json;
const pursuits = $('Fetch Open Pursuits').all().map(i => i.json);

// Parse SAM entity data
let entity = {};
try {
  const ents = samRaw.entityData || samRaw.entities || [];
  entity = ents[0] || {};
} catch(e) {}

const reg = entity.entityRegistration || {};
const core = entity.coreData || {};
const assertions = entity.assertions || {};

// Extract entity details
const uei = reg.ueiSAM || 'N/A';
const cage = reg.cageCode || 'N/A';
const businessTypes = (reg.businessTypes || []).map(b => b.businessTypeDesc || b).join(', ');
const naicsList = (assertions.goodsAndServices?.naicsList || []).map(n => n.naicsCode || n);
const setAsides = (assertions.goodsAndServices?.sbaBusinessTypeList || []).map(s => s.sbaBusinessTypeDesc || s);
const registrationStatus = reg.registrationStatus || 'Unknown';
const expirationDate = reg.registrationExpirationDate || 'N/A';

// Score NAICS overlap with our pursuits
const pursuitsNaics = [...new Set(pursuits.map(p => p.naics_code).filter(Boolean))];
const naicsOverlap = naicsList.filter(n => pursuitsNaics.includes(n));
const naicsScore = Math.min(10, naicsOverlap.length * 2 + (naicsOverlap.length > 0 ? 3 : 0));

// Score business type fit (8a, SDVOSB, WOSB, HUBZone = high value)
const highValueTypes = ['8(a)', 'SDVOSB', 'WOSB', 'HUBZone', 'Small Business'];
const setAsideScore = setAsides.some(s => highValueTypes.some(h => s.includes(h))) ? 8 : 4;

// Score registration health
const regScore = registrationStatus === 'Active' ? 10 : 3;

// Manually provided scores from caller
const pastPerfScore = Math.min(10, parseInt(body.past_performance_score) || 5);
const relationshipScore = Math.min(10, parseInt(body.relationship_score) || 5);
const capacityScore = Math.min(10, parseInt(body.capacity_score) || 5);

// Weighted composite
const weights = { naics: 0.25, set_aside: 0.20, relationship: 0.20, past_perf: 0.20, capacity: 0.10, reg: 0.05 };
const composite = (
  naicsScore * weights.naics +
  setAsideScore * weights.set_aside +
  relationshipScore * weights.relationship +
  pastPerfScore * weights.past_perf +
  capacityScore * weights.capacity +
  regScore * weights.reg
);
const teamingScore = Math.round(composite * 10);

// Recommendation
let recommendation = 'LOW FIT';
if (teamingScore >= 75) recommendation = 'STRONG TEAM';
else if (teamingScore >= 55) recommendation = 'VIABLE TEAM';
else if (teamingScore >= 40) recommendation = 'CONDITIONAL';

// Find best pursuit matches
const bestMatches = pursuits
  .filter(p => naicsOverlap.includes(p.naics_code))
  .slice(0, 3)
  .map(p => ({ opp_id: p.id, title: p.opp_title, agency: p.agency, gate: p.gate_stage }));

return [{ json: {
  status: 'ok',
  company_name: body.company_name,
  uei, cage,
  registration_status: registrationStatus,
  registration_expires: expirationDate,
  business_types: businessTypes,
  naics_codes: naicsList,
  set_asides: setAsides,
  naics_overlap: naicsOverlap,
  teaming_score: teamingScore,
  recommendation,
  score_breakdown: {
    naics_overlap: naicsScore,
    set_aside_value: setAsideScore,
    relationship: relationshipScore,
    past_performance: pastPerfScore,
    capacity: capacityScore,
    registration: regScore
  },
  best_pursuit_matches: bestMatches,
  scored_by: body.scored_by || 'GDA Command',
  scored_at: new Date().toISOString()
}}];
